/*===================================================================================================================================*/
/*  U1      u1_g_Fpcall_u1_And(const FP_U1_AND * fp_ap_U1_AND, const U2 u2_a_NC)                                                     */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      -                                                                                                                */
/*  Return:         -                                                                                                                */
/*===================================================================================================================================*/
U1      u1_g_Fpcall_u1_And(const FP_U1_AND * fp_ap_U1_AND, const U2 u2_a_NC)
{
    U4     u4_t_lpcnt;
    U1     u1_t_and;

    u1_t_and = (U1)TRUE;
    for(u4_t_lpcnt = (U4)0U; u4_t_lpcnt < (U4)u2_a_NC; u4_t_lpcnt++){
        u1_t_and &= (*fp_ap_U1_AND[u4_t_lpcnt])();
    }

    return(u1_t_and);
}
